def parse_amount(s):
    import re
    try:
        if s is None:
            return 0.0
        if not isinstance(s, str):
            return 0.0
        s = s.strip()
        if not s:
            return 0.0
        # Check for negative sign
        negative = False
        if s.startswith('-'):
            negative = True
            s = s[1:]
        elif s.startswith('+'):
            s = s[1:]
        # Remove dollar sign and whitespace
        s = s.replace('$', '').replace(' ', '').replace(',', '')
        if not s:
            return 0.0
        # Validate that it's a valid number
        if not re.match(r'^\d+(\.\d+)?$', s):
            return 0.0
        result = float(s)
        if negative:
            result = -result
        return result
    except:
        return 0.0

