def total(entries):
    try:
        from functools import reduce
        if not entries:
            return 0.0
        return round(reduce(lambda a, b: a + b, [e.get('amount', 0.0) for e in entries if isinstance(e, dict) and 'amount' in e]), 2)
    except Exception:
        return 0.0

